 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { Flex, Text } from '@patternfly/react-core';
 7	
 8	import CloudInitCredentialsContent from './CloudInitCredentialsContent';
 9	
10	import './cloud-init-credentials.scss';
11	
12	type CloudInitCredentialsProps = {
13	  isStandAlone?: boolean;
14	  vm: V1VirtualMachine;
15	};
16	
17	const CloudInitCredentials: FC<CloudInitCredentialsProps> = ({ vm }) => {
18	  const { t } = useKubevirtTranslation();
19	
20	  return (
21	    <Flex className="cloud-init-credentials">
22	      <Text className="cloud-init-credentials-title" component="h6">
23	        {t('Guest login credentials')}
24	      </Text>
25	      <HelpTextIcon
26	        bodyContent={t(
27	          'The following credentials for this operating system were created via cloud-init. If unsuccessful, cloud-init could be improperly configured. Contact the image provider for more information.',
28	        )}
29	      />
30	      <CloudInitCredentialsContent vm={vm} />
31	    </Flex>
32	  );
33	};
34	
35	export default CloudInitCredentials;

